class IsPhoneNumber(DirtyEquals[str]):
    """
    A class that checks if a value is a valid phone number, optionally restricting validation to a specific
    country's national/international formats.
    """

    # generic international format: '+' followed by a country code and 7-15 digits, e.g. +33 1 42 68 53 00
    _generic_international_re = re.compile(r'^\+\d{8,15}$')
    # generic national format: 7-15 digits, no country code, e.g. 555-123-4567
    _generic_national_re = re.compile(r'^\d{7,15}$')

    # country specific national/international patterns, digits only (after stripping common delimiters)
    _country_patterns = {
        'US': {
            'national': re.compile(r'^\d{10}$'),
            'international': re.compile(r'^\+1\d{10}$'),
        },
        'GB': {
            'national': re.compile(r'^0\d{9,10}$'),
            'international': re.compile(r'^\+44\d{9,10}$'),
        },
    }

    def __init__(self, country: Optional[str] = None):
        """
        Args:
            country: optional ISO 3166-1 alpha-2 country code used to validate the phone number against that
                country's national or international format. If omitted, generic validation is used which accepts
                any reasonably formatted national or international phone number.

        ```py title="IsPhoneNumber"
        from dirty_equals import IsPhoneNumber

        assert '+1-555-123-4567' == IsPhoneNumber
        assert '555-123-4567' == IsPhoneNumber
        assert '555-123-4567' == IsPhoneNumber('US')
        assert '+1-555-123-4567' == IsPhoneNumber('US')
        assert '020 7946 0958' == IsPhoneNumber('GB')
        assert '+44 20 7946 0958' == IsPhoneNumber('GB')
        assert '555-123-4567' != IsPhoneNumber('GB')
        assert 12345 != IsPhoneNumber
        ```
        """
        self.country = country.upper() if country else None
        super().__init__(plain_repr('*') if self.country is None else self.country)

    def equals(self, other: Any) -> bool:
        if not isinstance(other, str):
            return False

        cleaned = re.sub(r'[\s\-.()]', '', other)
        if not re.fullmatch(r'\+?\d+', cleaned or ''):
            return False

        if self.country is None:
            return bool(self._generic_international_re.fullmatch(cleaned) or self._generic_national_re.fullmatch(
                cleaned
            ))

        patterns = self._country_patterns.get(self.country)
        if patterns is None:
            # unknown country: fall back to generic international validation
            return bool(self._generic_international_re.fullmatch(cleaned))

        if cleaned.startswith('+'):
            return bool(patterns['international'].fullmatch(cleaned))
        else:
            return bool(patterns['national'].fullmatch(cleaned))

